n=A.b(["\u0110\u0103ng k\xfd, \u0111\u0103ng nh\u1eadp v\xe0 x\xe1c minh t\xe0i kho\u1ea3n","X\xe1c th\u1ef1c sinh tr\u1eafc h\u1ecdc t\xf9y ch\u1ecdn (v\xe2n tay/nh\u1eadn di\u1ec7n khu\xf4n m\u1eb7t) \u0111\u1ec3 truy c\u1eadp nhanh v\xe0 an to\xe0n","Qu\u1ea3n l\xfd c\xf4ng vi\u1ec7c, l\u1ecbch tr\xecnh v\xe0 t\u1ed5 ch\u1ee9c cu\u1ed9c h\u1ecdp","Qu\u1ea3n l\xfd nhi\u1ec7m v\u1ee5: xem, giao v\xe0 nh\u1eadn nhi\u1ec7m v\u1ee5","Xem v\xe0 \u0111\u1eb7t ph\u01b0\u01a1ng ti\u1ec7n di chuy\u1ec3n cho c\xe1c chuy\u1ebfn \u0111i theo l\u1ecbch"],p)
