l=A.kw(A.b(["Estimated contribution: 16% of the project","Optimized and refactored the codebase. Cleaned up legacy code, applied best practices for state management, and improved responsiveness.","Updated the UI in collaboration with the Designer","Managed tasks: assigned and received tasks, updated statistics for assigned tasks and directed tasks."],p),A.b(["\u0110\xf3ng g\xf3p \u01b0\u1edbc t\xednh 16% d\u1ef1 \xe1n","T\u1ed1i \u01b0u h\xf3a v\xe0 t\xe1i c\u1ea5u tr\xfac m\xe3. D\u1ecdn d\u1eb9p m\xe3 ngu\u1ed3n c\u0169, \xe1p d\u1ee5ng c\xe1c ph\u01b0\u01a1ng ph\xe1p qu\u1ea3n l\xfd tr\u1ea1ng th\xe1i t\u1ed1t nh\u1ea5t v\xe0 n\xe2ng cao kh\u1ea3 n\u0103ng ph\u1ea3n h\u1ed3i.","C\u1eadp nh\u1eadt l\u1ea1i giao di\u1ec7n, ph\u1ed1i h\u1ee3p c\xf9ng Designer","Qu\u1ea3n l\xfd nhi\u1ec7m v\u1ee5, giao v\xe0 nh\u1eadn nhi\u1ec7m v\u1ee5, c\u1eadp nh\u1eadt th\u1ed1ng k\xea nhi\u1ec7m v\u1ee5 \u0111\u01b0\u1ee3c giao, nhi\xeam v\u1ee5 ch\u1ec9 \u0111\u1ea1o."],p),"The application assists users working in the Ministry of Information office.","\u1ee8ng d\u1ee5ng h\u1ed7 tr\u1ee3 ng\u01b0\u1eddi d\xf9ng l\xe0m vi\u1ec7c t\u1ea1i v\u0103n ph\xf2ng B\u1ed9 Th\xf4ng tin.","assets/qldh.png",o,n,"Qu\u1ea3n l\xfd \u0111i\u1ec1u h\xe0nh","https://apps.apple.com/vn/app/one-mst/id1562108303?l=vi","https://play.google.com/store/apps/details?id=com.xtel.bookmetting_car&pcampaignid=web_share",g,a5,l)
