m=A.b(["Qu\xe9t CCCD/h\u1ed9 chi\u1ebfu v\xe0 tr\xedch xu\u1ea5t th\xf4ng tin hi\u1ec3n th\u1ecb","Ch\u1ee5p \u1ea3nh kh\xe1ch h\xe0ng v\xe0 x\xe1c minh danh t\xednh v\u1edbi ph\xe1t hi\u1ec7n s\u1ed1ng (c\u01b0\u1eddi, nh\xe1y m\u1eaft, quay tr\xe1i/ph\u1ea3i)","X\xe1c nh\u1eadn ch\u1eef k\xfd kh\xe1ch h\xe0ng","\u0110\xe1nh gi\xe1 d\u1ecbch v\u1ee5 v\xe0 ph\u1ea3n h\u1ed3i"],p)
o=A.kw(A.b([a1,a2],p),A.b([a3,a4],p),"Viettel Verify ID app enables fast and secure identity verification by scanning ID documents, performing face matching with liveness detection, and capturing user signatures.","\u1ee8ng d\u1ee5ng Viettel Verify ID cho ph\xe9p x\xe1c minh danh t\xednh nhanh ch\xf3ng v\xe0 an to\xe0n b\u1eb1ng c\xe1ch qu\xe9t gi\u1ea5y t\u1edd t\xf9y th\xe2n, \u0111\u1ed1i chi\u1ebfu khu\xf4n m\u1eb7t v\u1edbi ph\xe1t hi\u1ec7n s\u1ed1ng v\xe0 thu th\u1eadp ch\u1eef k\xfd ng\u01b0\u1eddi d\xf9ng.","assets/viettel.png",l,m,"Viettel verify ID",g,g,g,"1",o)
